const scrollBtn=document.getElementById('scrollTopBtn');function toggleScrollButton(){if(!scrollBtn)return;if(window.scrollY>300){scrollBtn.classList.add('show')}else{scrollBtn.classList.remove('show')}}window.addEventListener('scroll',toggleScrollButton);window.addEventListener('load',toggleScrollButton);if(scrollBtn){scrollBtn.addEventListener('click',function(e){e.preventDefault();window.scrollTo({top: 0,behavior: 'smooth'})})}